// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.lmdb.benchmark;

import java.io.IOException;
import java.lang.reflect.Field;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import java.nio.file.Path;
import java.util.concurrent.atomic.AtomicLong;

import org.eclipse.rdf4j.benchmark.common.ThemeQueryCatalog;
import org.eclipse.rdf4j.benchmark.rio.util.ThemeDataSetGenerator;
import org.eclipse.rdf4j.benchmark.rio.util.ThemeDataSetGenerator.Theme;
import org.eclipse.rdf4j.common.transaction.IsolationLevels;
import org.eclipse.rdf4j.query.explanation.Explanation;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.repository.util.RDFInserter;
import org.eclipse.rdf4j.sail.lmdb.LmdbStore;
import org.junit.jupiter.api.Assertions;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/**
 * Scratch diagnostic (Routine C) for the ELECTRICAL_GRID #2 regression: the native aggregate path routes the query
 * through reshapeLeftJoinForFactorization + FactorizedTail and loses the selective VALUES-driven join order. This test
 * executes the query with executed-level explain telemetry so the native engine's chosen entry plan, execution path,
 * strategy-proposal costs and prefix strategy are all logged, together with wall-clock timings.
 *
 * Toggle the native strategies from the command line for A/B runs: -Drdf4j.lmdb.factorizedTail.enabled=false and/or
 * -Drdf4j.lmdb.factorizedSink.enabled=false
 */
class LmdbGridQ2FactorizedDiagnosticIT {

	private static final Theme THEME = Theme.ELECTRICAL_GRID;
	private static final int QUERY_INDEX = 2;
	private static final int WARMUP_RUNS = 5;
	private static final int MEASURED_RUNS = 10;

	@Test
	void diagnoseFactorizedTailPath(@TempDir Path dataDir) throws Exception {
		Path storeDir = dataDir.resolve("grid-q2-diagnostic");
		loadWithEstimatorDisabled(storeDir);
		prepareEstimatorSnapshot(storeDir);

		String query = ThemeQueryCatalog.queryFor(THEME, QUERY_INDEX);
		System.out.println("=== Query (ELECTRICAL_GRID #" + QUERY_INDEX + ") ===");
		System.out.println(query);
		System.out.println("factorizedTail.enabled=" + System.getProperty("rdf4j.lmdb.factorizedTail.enabled"));
		System.out.println("factorizedSink.enabled=" + System.getProperty("rdf4j.lmdb.factorizedSink.enabled"));

		LmdbStore store = new LmdbStore(storeDir.toFile(), ConfigUtil.createConfig());
		SailRepository repository = new SailRepository(store);
		try {
			long resultCount = timeAndCount(repository, query, "cold");
			for (int i = 0; i < WARMUP_RUNS; i++) {
				timeAndCount(repository, query, "warmup-" + i);
			}
			long[] samples = new long[MEASURED_RUNS];
			for (int i = 0; i < MEASURED_RUNS; i++) {
				long start = System.nanoTime();
				long count = executeQuery(repository, query);
				samples[i] = System.nanoTime() - start;
				Assertions.assertEquals(resultCount, count, "result count changed between runs");
			}
			long min = Long.MAX_VALUE;
			long max = Long.MIN_VALUE;
			long sum = 0;
			for (long sample : samples) {
				min = Math.min(min, sample);
				max = Math.max(max, sample);
				sum += sample;
			}
			System.out.printf("=== Measured (%d runs): min=%.3f ms avg=%.3f ms max=%.3f ms, results=%d ===%n",
					MEASURED_RUNS, min / 1e6, sum / 1e6 / MEASURED_RUNS, max / 1e6, resultCount);

			dumpNativeCounters("before executed explain");
			try (SailRepositoryConnection connection = repository.getConnection()) {
				Explanation explanation = connection.prepareTupleQuery(query)
						.explain(Explanation.Level.Executed);
				System.out.println("=== Executed explain (native telemetry) ===");
				System.out.println(explanation);
			}
			dumpNativeCounters("after executed explain");
		} finally {
			repository.shutDown();
		}
	}

	private static long timeAndCount(SailRepository repository, String query, String label) {
		long start = System.nanoTime();
		long count = executeQuery(repository, query);
		System.out.printf("run[%s]: %.3f ms (%d results)%n", label, (System.nanoTime() - start) / 1e6, count);
		return count;
	}

	private static long executeQuery(SailRepository repository, String query) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			return connection.prepareTupleQuery(query)
					.evaluate()
					.stream()
					.count();
		}
	}

	/**
	 * The FactorizedTail counters live in a package-private class; reflection keeps this scratch test self-contained.
	 */
	private static void dumpNativeCounters(String label) {
		try {
			Class<?> tail = Class.forName("org.eclipse.rdf4j.sail.lmdb.evaluation.FactorizedTail");
			System.out.printf("FactorizedTail counters (%s): engaged=%d scanOnceBuilds=%d memoBypasses=%d%n", label,
					readCounter(tail, "ENGAGED"), readCounter(tail, "SCAN_ONCE_BUILDS"),
					readCounter(tail, "MEMO_BYPASSES"));
		} catch (ReflectiveOperationException e) {
			System.out.println("FactorizedTail counters unavailable: " + e);
		}
	}

	private static long readCounter(Class<?> owner, String name) throws ReflectiveOperationException {
		Field field = owner.getDeclaredField(name);
		field.setAccessible(true);
		return ((AtomicLong) field.get(null)).get();
	}

	private static void loadWithEstimatorDisabled(Path storeDirectory) throws Exception {
		LmdbStore store = new LmdbStore(storeDirectory.toFile(), ConfigUtil.createBulkLoadConfig());
		SailRepository repository = new SailRepository(store);
		try {
			try (SailRepositoryConnection connection = repository.getConnection()) {
				connection.begin(IsolationLevels.NONE);
				RDFInserter inserter = new RDFInserter(connection);
				ThemeDataSetGenerator.generate(THEME, inserter);
				connection.commit();
			}
		} finally {
			shutdownAndRelease(repository, store);
		}
	}

	private static void prepareEstimatorSnapshot(Path storeDirectory) throws Exception {
		LmdbStore store = new LmdbStore(storeDirectory.toFile(), ConfigUtil.createConfig());
		SailRepository repository = new SailRepository(store);
		try {
			BenchmarkJoinEstimatorSupport.prepareEstimatorForBulkLoad(repository, store);
			persistEstimatorAfterBulkLoad(repository, store);
			BenchmarkJoinEstimatorSupport.persistStoreStatistics(store);
		} finally {
			shutdownAndRelease(repository, store);
		}
	}

	private static void persistEstimatorAfterBulkLoad(SailRepository repository, LmdbStore store) throws Exception {
		Method method = BenchmarkJoinEstimatorSupport.class.getDeclaredMethod("persistEstimatorAfterBulkLoad",
				SailRepository.class, LmdbStore.class);
		method.setAccessible(true);
		try {
			method.invoke(null, repository, store);
		} catch (InvocationTargetException e) {
			Throwable cause = e.getCause();
			if (cause instanceof Exception exception) {
				throw exception;
			}
			throw (Error) cause;
		}
	}

	private static void shutdownAndRelease(SailRepository repository, LmdbStore store) throws IOException {
		try {
			BenchmarkJoinEstimatorSupport.releaseEstimatorMemory(store);
		} finally {
			repository.shutDown();
		}
	}
}
